// Procura apenas anexos PDF
const item = items[0];
const binaryKeys = item.binary ? Object.keys(item.binary) : [];

let nomesAnexos = [];
let temPdf = false;
let chavePdf = null;

for (const key of binaryKeys) {
  const bin = item.binary[key];

  const fileName = (bin.fileName || "").toLowerCase();
  const mimeType = (bin.mimeType || "").toLowerCase();

  const isPdf =
    fileName.endsWith(".pdf") ||
    mimeType === "application/pdf";

  if (isPdf) {
    nomesAnexos.push(bin.fileName || key);

    if (!temPdf) {
      temPdf = true;
      chavePdf = key;
    }
  }
}

item.json.anexos_nomes = nomesAnexos.join(", ");
item.json.tem_anexo_pdf = temPdf;
item.json.anexo_binary_key = chavePdf;

return [item];

