// Faz o parse robusto do JSON retornado pela IA
const item = items[0];

let textoResposta = '';
if (item.json.message && item.json.message.content) {
  textoResposta = item.json.message.content;
} else if (item.json.content) {
  textoResposta = item.json.content;
} else if (typeof item.json.text === 'string') {
  textoResposta = item.json.text;
} else {
  textoResposta = JSON.stringify(item.json);
}

textoResposta = textoResposta.replace(/```json/gi, '').replace(/```/g, '').trim();

let resultado;
try {
  resultado = JSON.parse(textoResposta);
} catch (e) {
  resultado = {
    is_nota_fiscal: false,
    motivo: 'Falha ao interpretar resposta da IA: ' + e.message,
    dados: null
  };
}

return [{ json: resultado }];

// Corrige e-mails que chegam com encoding trocado (mojibake),
// deixando tudo em UTF-8 padrão Brasil (aceita ç, ã, õ, á, é, ~, ^ etc.)

function corrigirTexto(str) {
  if (typeof str !== 'string' || str.length === 0) return str;

  const temMojibake = /Ã[\x80-\xBF]|Â[\x80-\xBF]/.test(str);
  if (!temMojibake) return str;

  try {
    const corrigido = Buffer.from(str, 'latin1').toString('utf8');
    if (!corrigido.includes('\uFFFD')) return corrigido;
  } catch (e) {
    // se der erro, mantém o texto original
  }
  return str;
}

function corrigirObjeto(obj, profundidade = 0) {
  if (profundidade > 2 || obj === null || typeof obj !== 'object') return obj;
  for (const chave of Object.keys(obj)) {
    const valor = obj[chave];
    if (typeof valor === 'string') {
      obj[chave] = corrigirTexto(valor);
    } else if (typeof valor === 'object' && valor !== null) {
      corrigirObjeto(valor, profundidade + 1);
    }
  }
  return obj;
}

return items.map(item => {
  corrigirObjeto(item.json);
  return item;
});

